import json
# Manuelle Extraktion der Fahrerdaten
# Fehlende Fahrerprofile, die die meisten Erscheinungen in unseren Daten haben
# Via Screenshot und Google Gemini Tool


PATCH_FILE = "../../../data/raw/riders_full_biometrics.jsonl"

def add_manual_riders(riders_list):
    with open(PATCH_FILE, "a", encoding="utf-8") as f:
        for rider in riders_list:
            # json.dumps ohne indent sorgt dafür, dass der Fahrer in GENAU EINER Zeile landet
            # wichtig für Format
            line = json.dumps(rider, ensure_ascii=False)
            f.write(line + "\n")
            print(f"✅ Einzeilig hinzugefügt: {rider['url_name']}")

